output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?disorder ?disorderLabel ?symptom ?symptomLabel ?treatment ?treatmentLabel WHERE {
  VALUES ?disorder {
    wd:Q42844 wd:Q845224 wd:Q281928 wd:Q1051223
  }
  OPTIONAL {
    ?disorder rdfs:label ?disorderLabel .
    FILTER(lang(?disorderLabel) = "en")
  }
  OPTIONAL {
    ?disorder wdt:P2750 ?symptom .
  }
  OPTIONAL {
    ?symptom rdfs:label ?symptomLabel .
    FILTER(lang(?symptomLabel) = "en")
  }
  OPTIONAL {
    ?disorder wdt:P2862 ?treatment .
  }
  OPTIONAL {
    ?treatment rdfs:label ?treatmentLabel .
    FILTER(lang(?treatmentLabel) = "en")
  }
}

